  border-radius: 9999px;
  font-size: 14px;
  font-weight: 500;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  transition: all 0.3s ease;
}

.btn-gold:hover {
  background: var(--brown-dark);
  transform: scale(1.02);
